from collections import Counter

class Solution:
    def validSubstringCount(self, word1, word2):
        n = len(word1)
        req = Counter(word2)
        total = 0
        for i in range(n):
            cnt = Counter()
            for j in range(i, n):
                cnt[word1[j]] += 1
                if all(cnt[c] >= req[c] for c in req):
                    total += 1
        return total

