class Solution:
    def validSubstringCount(self, word1, word2):
        n, m = len(word1), len(word2)
        if m > n:
            return 0
        req = [0] * 26
        for c in word2:
            req[ord(c) - 97] += 1
        have = [0] * 26
        missing = sum(1 for x in req if x > 0)
        count = 0
        left = 0
        for right in range(n):
            c = ord(word1[right]) - 97
            have[c] += 1
            if req[c] and have[c] == req[c]:
                missing -= 1
            while missing == 0:
                count += n - right
                lc = ord(word1[left]) - 97
                if req[lc] and have[lc] == req[lc]:
                    missing += 1
                have[lc] -= 1
                left += 1
        return count

