var validSubstringCount = function(word1, word2) {
    const n = word1.length, m = word2.length;
    if (m > n) return 0;
    const req = new Array(26).fill(0);
    for (let i = 0; i < m; i++) req[word2.charCodeAt(i) - 97]++;
    const have = new Array(26).fill(0);
    let missing = req.filter(x => x > 0).length;
    let count = 0;
    let left = 0;
    for (let right = 0; right < n; right++) {
        const c = word1.charCodeAt(right) - 97;
        have[c]++;
        if (req[c] && have[c] === req[c]) missing--;
        while (missing === 0) {
            count += n - right;
            const lc = word1.charCodeAt(left) - 97;
            if (req[lc] && have[lc] === req[lc]) missing++;
            have[lc]--;
            left++;
        }
    }
    return count;
};
